// Cache for lazy-loaded full chapter data
const _chapterCache = new Map();

/**
 * Lazy-load full chapter data (vocab, grammar, workbook, exam, etc.)
 * Subsequent calls for the same ID are served from cache.
 * @param {number} id - chapter ID (0-50)
 * @returns {Promise<object>} Full chapter data object
 */
export async function loadChapter(id) {
  if (_chapterCache.has(id)) return _chapterCache.get(id);
  const mod = await import(`./chapters/chapter_${id}.json`);
  const data = mod.default;
  _chapterCache.set(id, data);
  return data;
}
